#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int n;
    scanf("%d", &n);
    int *heights = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &heights[i]);
    }
    qsort(heights, n, sizeof(int), compare);
    int chairs = n;
    printf("%d\n", chairs);
    free(heights);
    return 0;
}

